INSERT INTO module_tickets(key,value) VALUES('editorConfig','{"title":"Tickets","description":"Private-thread ticket panels per category. Configure each type, save, then publish its panel to Discord.","fields":[{"key":"disabled","label":"Module disabled message","type":"text","store":"texts"},{"key":"noPermission","label":"No permission message","type":"text","store":"texts"},{"key":"noDeletePermission","label":"No delete permission message","type":"text","store":"texts"},{"key":"deleteNotClosed","label":"Delete on open ticket message","type":"text","store":"texts"},{"key":"categoryUnpublished","label":"Category unavailable message","type":"text","store":"texts"},{"key":"channelNotConfigured","label":"Channel not configured message","type":"text","store":"texts"},{"key":"invalidChannel","label":"Invalid channel message","type":"text","store":"texts"},{"key":"openError","label":"Open error message","type":"text","store":"texts"},{"key":"closeError","label":"Close error message","type":"text","store":"texts"},{"key":"deleteError","label":"Delete error message","type":"text","store":"texts"},{"key":"closeCancelled","label":"Close cancelled message","type":"text","store":"texts"},{"key":"deleteCancelled","label":"Delete cancelled message","type":"text","store":"texts"},{"key":"threadContextRequired","label":"Wrong context message","type":"text","store":"texts"},{"key":"invalidInteraction","label":"Mismatched button message","type":"text","store":"texts"},{"key":"openInProgress","label":"Open in progress message","type":"text","store":"texts"},{"key":"roleActionError","label":"Role action error message","type":"text","store":"texts"},{"key":"roleActionHierarchyError","label":"Role action hierarchy error message","type":"text","store":"texts"},{"key":"roleActionOpenerMissing","label":"Role action opener missing message","type":"text","store":"texts"},{"key":"ticketTypes","label":"Ticket types","type":"object-list","store":"config","itemLabel":"Ticket type","publishable":true,"collapsible":true,"defaultItem":{"id":"","published":false,"openButtonLabel":"Open ticket","panelTitle":"Support","panelDescription":"","emoji":"","channelId":"","staffRoleId":"","deniedRoleIds":[],"roleActionRoleId":"","roleDenied":"You cannot open a ticket in this category.","ticketWelcome":"Hi {mention}, describe your issue and staff will assist you.","closeButtonLabel":"Close ticket","roleActionButtonLabel":"Grant role","roleActionConfirmation":"{mention} was given {role}.","confirmClosePrompt":"Close this ticket?","confirmCloseYes":"Yes, close","confirmCloseNo":"Cancel","ticketClosed":"This ticket has been closed.","deleteButtonLabel":"DELETE","confirmDeletePrompt":"Delete this closed ticket permanently?","confirmDeleteYes":"Yes, delete","confirmDeleteNo":"Cancel","ticketDeleted":"Ticket deleted.","alreadyOpen":"You already have an open ticket in this category.","openSuccess":"Your ticket was created: {thread}"},"itemFields":[{"key":"emoji","label":"Button emoji (optional)","type":"text","store":"config"},{"key":"channelId","label":"Channel","type":"channel","store":"config","help":"Panel is posted here; ticket threads are created here."},{"key":"staffRoleId","label":"Staff role","type":"role","store":"config"},{"key":"deniedRoleIds","label":"Denied roles","type":"role-multi","store":"config","help":"Users with any of these roles cannot open this ticket type. Leave empty to disable."},{"key":"roleActionRoleId","label":"Role action role (optional)","type":"role","store":"config","help":"When set, staff can use a green button on the welcome message to grant this role to the opener and close the ticket."},{"key":"roleDenied","label":"Denied role message","type":"textarea","store":"texts"},{"key":"openButtonLabel","label":"Open button label","type":"text","store":"texts"},{"key":"panelTitle","label":"Panel title","type":"text","store":"texts"},{"key":"panelDescription","label":"Panel description","type":"textarea","store":"texts"},{"key":"ticketWelcome","label":"Welcome message","type":"textarea","store":"texts","maxLength":4096,"help":"Tokens: {mention}. Max 4096 characters. Text over 2000 characters is sent as an embed automatically."},{"key":"closeButtonLabel","label":"Close button label","type":"text","store":"texts"},{"key":"roleActionButtonLabel","label":"Role action button label","type":"text","store":"texts"},{"key":"roleActionConfirmation","label":"Role action confirmation","type":"textarea","store":"texts","help":"Posted in the channel when staff use the role action button. Tokens: {mention}, {role}"},{"key":"confirmClosePrompt","label":"Close confirm prompt","type":"textarea","store":"texts"},{"key":"confirmCloseYes","label":"Confirm button label","type":"text","store":"texts"},{"key":"confirmCloseNo","label":"Cancel button label","type":"text","store":"texts"},{"key":"ticketClosed","label":"Closed message","type":"textarea","store":"texts"},{"key":"deleteButtonLabel","label":"Delete button label","type":"text","store":"texts"},{"key":"confirmDeletePrompt","label":"Delete confirm prompt","type":"textarea","store":"texts"},{"key":"confirmDeleteYes","label":"Delete confirm button label","type":"text","store":"texts"},{"key":"confirmDeleteNo","label":"Delete cancel button label","type":"text","store":"texts"},{"key":"ticketDeleted","label":"Deleted confirmation (ephemeral)","type":"textarea","store":"texts"},{"key":"alreadyOpen","label":"Already open message","type":"textarea","store":"texts","help":"Tokens: {thread}"},{"key":"openSuccess","label":"Open success (ephemeral)","type":"textarea","store":"texts","help":"Tokens: {thread}"}]}]}') ON CONFLICT(key) DO UPDATE SET value=excluded.value;
